module LDO_Regulator(  
    input wire [7:0] obf_Vin,    // 8-bit input voltage  
    input wire enable,       // Enable signal  
    output reg [7:0] Vout    // 8-bit output voltage  
);  
    always @(*) begin  
        if (enable)  
            Vout = obf_Vin;  
        else  
            Vout = 8'b0;  
    end  
endmodule
